@app.route("/reset-mfa/confirm", methods=["GET"])
def confirm_mfa_reset():
    token = request.args.get("token", "")
    if not token:
        return jsonify({"error": "missing token"}), 400

    try:
        payload = verify_reset_token(token, app.config["RESET_TOKEN_MAX_AGE_SECONDS"])
    except SignatureExpired:
        return jsonify({"error": "reset link expired"}), 400
    except BadSignature:
        return jsonify({"error": "invalid reset link"}), 400

    email = payload.get("email")
    nonce = payload.get("nonce")
    user = users.get(email)

    if not user or not nonce or user.get("pending_reset_nonce") != nonce:
        return jsonify({"error": "invalid or already used reset link"}), 400

    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["mfa_backup_codes"] = []
    user["pending_reset_nonce"] = None
    user["last_mfa_reset_at"] = int(time.time())

    return jsonify({
        "message": "MFA has been reset. You can now log in using only your password."
    }), 200

